import { buildGraph, computeReachability, detectCycle } from '../Graph.js';
import { isBookendTask } from '../task-utils.js';

/**
 * Auto-serializes concurrent tasks whose focusAreas overlap (or whose scope is
 * 'root' / includes '*'), preventing file-level conflicts at runtime.
 *
 * This is the canonical, optimised implementation (bulk-accumulate pattern):
 *   Phase A — collects all new edges without rebuilding the graph. Pairs
 *             are generated by bucketing tasks by focus area so we only
 *             consider candidates that can actually overlap, degrading to
 *             the full pairwise scan only for globally-scoped tasks.
 *   Phase B — applies all edges in one pass, rebuilds once, re-checks for cycles.
 *
 * Both generate-playbook.js (generateFromManifest) and PlaybookOrchestrator
 * delegate here so the algorithm is defined exactly once.
 *
 * Bookend tasks are excluded: they do not perform file edits and serialising
 * them would produce incorrect dependency orderings.
 *
 * @param {object} manifest    — The sprint manifest (tasks array is mutated in place).
 * @param {Map}    adjacency   — The initial adjacency list (from buildGraph).
 * @param {object} [opts]
 * @param {Map}    [opts.reachable] — Pre-computed reachability matrix. When
 *   provided, the analyzer will reuse it instead of re-running
 *   `computeReachability(adjacency)`; callers that run multiple planning
 *   passes on the same graph can compute once and share the result.
 * @returns {{ finalAdjacency: Map, graphMutated: boolean, reachable: Map }}
 *   `reachable` is the matrix that was used for the pass — either the one
 *   passed in or the freshly computed one. When `graphMutated` is true the
 *   matrix is stale and callers must recompute before reuse.
 */
export function autoSerializeOverlaps(manifest, adjacency, opts = {}) {
  // Pre-compute focus-area Sets for O(1) intersection checks
  const focusSets = new Map(
    manifest.tasks.map((t) => [
      t.id,
      new Set(Array.isArray(t.focusAreas) ? t.focusAreas : []),
    ]),
  );

  const reachable = opts.reachable ?? computeReachability(adjacency);
  const pendingEdges = _collectPendingEdges(
    manifest.tasks,
    focusSets,
    reachable,
  );

  // Phase B: apply all collected edges in a single pass & rebuild once
  const graphMutated = pendingEdges.length > 0;
  if (graphMutated) {
    applyNewDependencies(manifest.tasks, pendingEdges);

    const updatedGraph = buildGraph(manifest.tasks);
    const finalAdjacency = updatedGraph.adjacency;
    const cycle = detectCycle(finalAdjacency);

    if (cycle) {
      throw new Error(
        `Dependency cycle detected after auto-serialization: ${cycle.join(' → ')}`,
      );
    }
    return { finalAdjacency, graphMutated, reachable };
  }

  return { finalAdjacency: adjacency, graphMutated: false, reachable };
}

/**
 * Internal helper to apply new edges to the task manifest efficiently.
 * Uses a Set-based lookup to ensure O(1) duplicate checks during the merge.
 *
 * @param {object[]} tasks  — Array of tasks to update.
 * @param {Array[]}  edges  — List of [fromId, toId] pairs.
 */
function applyNewDependencies(tasks, edges) {
  const taskMap = new Map(tasks.map((t) => [t.id, t]));
  const depSets = new Map();

  for (const [fromId, toId] of edges) {
    const task = taskMap.get(toId);
    if (!task) continue;

    task.dependsOn ??= [];

    if (!depSets.has(toId)) {
      depSets.set(toId, new Set(task.dependsOn));
    }

    const set = depSets.get(toId);
    if (!set.has(fromId)) {
      set.add(fromId);
      task.dependsOn.push(fromId);
    }
  }
}

/**
 * Internal helper to find all pairs of tasks that overlap but don't yet have
 * a dependency ordering between them.
 *
 * Candidate generation uses focus-area bucketing — tasks are grouped by
 * shared focus area, and only pairs within the same bucket are considered.
 * Globally-scoped tasks (`scope === 'root'` or `focusAreas` contains `*`)
 * overlap with every other task, so they are paired against the full set.
 * This collapses the expected run-time from O(n²) to O(n + overlaps) on
 * manifests where focus areas are disjoint.
 *
 * @param {object[]} tasks     — The array of tasks to check.
 * @param {Map}      focusSets — Map of taskId to Set of focus areas.
 * @param {Map}      reachable — Reachability matrix to check existing paths.
 * @returns {Array[]}            List of [fromId, toId] pairs.
 */
function _collectPendingEdges(tasks, focusSets, reachable) {
  const pendingEdges = [];
  const seenPairs = new Set();

  // Index active tasks by position (for deterministic lower-index-first
  // ordering) and bucket them by focus area.
  const order = new Map();
  const buckets = new Map();
  const globals = [];
  for (let i = 0; i < tasks.length; i++) {
    const t = tasks[i];
    if (isBookendTask(t)) continue;
    order.set(t.id, i);

    const set = focusSets.get(t.id);
    const isGlobal = t.scope === 'root' || set.has('*');
    if (isGlobal) {
      globals.push(t);
      continue;
    }
    for (const area of set) {
      if (area === '*') continue;
      if (!buckets.has(area)) buckets.set(area, []);
      buckets.get(area).push(t);
    }
  }

  const tryEmit = (taskA, taskB) => {
    if (taskA.id === taskB.id) return;
    const ia = order.get(taskA.id);
    const ib = order.get(taskB.id);
    if (ia === undefined || ib === undefined) return;
    // Preserve the lower-index-first ordering the previous algorithm
    // produced so downstream edge direction is stable.
    const [from, to] = ia < ib ? [taskA, taskB] : [taskB, taskA];
    const key = `${from.id}|${to.id}`;
    if (seenPairs.has(key)) return;
    seenPairs.add(key);

    const fromReachesTo = reachable.get(from.id)?.has(to.id);
    const toReachesFrom = reachable.get(to.id)?.has(from.id);
    if (!fromReachesTo && !toReachesFrom) pendingEdges.push([from.id, to.id]);
  };

  // Within-bucket pairs — guaranteed to overlap on the bucket's area.
  for (const members of buckets.values()) {
    if (members.length < 2) continue;
    for (let i = 0; i < members.length; i++) {
      for (let j = i + 1; j < members.length; j++) {
        tryEmit(members[i], members[j]);
      }
    }
  }

  // Globals pair with every other active task (including other globals).
  for (const g of globals) {
    for (const [id, idx] of order.entries()) {
      if (id === g.id) continue;
      tryEmit(g, tasks[idx]);
    }
  }

  return pendingEdges;
}
